reports.queryTemplate:
select CO_PARTNO 'PartNo', CO_PARTNAME 'Part Name',sum(PS_QTY) 'Scheduled Qty', sum(PD_PRODQTY) 'Produced Qty'
from scheduled_production
left join components on PS_PARENTCOMPID= co_id
, production_details,schedule_master
where ps_id= PD_PSID
and PS_SMID = sm_id
and SM_MONTH= {month}
and SM_YEAR= {year}
group by co_partno,CO_PARTNAME
order by co_partno;
